<h1 class="h5 mb-3">Panel de empresa</h1><div class="row g-2 mb-3"><div class="col-md-3"><div class="card card-body small">Clientes: <strong><?= $resumen['total_clientes'] ?></strong></div></div><div class="col-md-3"><div class="card card-body small">Productos: <strong><?= $resumen['total_productos'] ?></strong></div></div><div class="col-md-3"><div class="card card-body small">Cotizaciones: <strong><?= $resumen['total_cotizaciones'] ?></strong></div></div><div class="col-md-3"><div class="card card-body small">Vence plan: <strong><?= e($resumen['fecha_vencimiento'] ?? 'N/D') ?></strong></div></div></div><div class="card"><div class="card-header small">Actividad reciente de cotizaciones</div><table class="table table-sm mb-0"><thead><tr><th>Número</th><th>Cliente</th><th>Total</th><th>Estado</th></tr></thead><tbody><?php foreach($cotizaciones as $c): ?><tr><td><?= e($c['numero']) ?></td><td><?= e($c['cliente']) ?></td><td>$<?= number_format((float)$c['total'],2) ?></td><td><span class="badge text-bg-light"><?= e($c['estado']) ?></span></td></tr><?php endforeach; ?></tbody></table></div>
